module KoggeStoneAdder (
    input [3:0] A,
    input [3:0] B,
    output [3:0] SUM,
    output COUT
);
    wire [3:0] P, G, C;
    wire [4:0] C_temp;

  assign COUT = C_temp[4];
  assign SUM = P ^ C_temp[3:0];

  assign C_temp[4] = G[3] | (P[3] & C_temp[3]);
  assign C_temp[3] = G[2] | (P[2] & C_temp[2]);
  assign C_temp[2] = G[1] | (P[1] & C_temp[1]);
  assign C_temp[1] = G[0];
  assign C_temp[0] = 0;

  assign G = A & B;
  assign P = A ^ B;

endmodule
